function getDexCreatorToken() {
  if (typeof window === "undefined") return null;
  return walletGetItem("auth_token");
}

async function dexCreatorAdminApi<T>(
  endpoint: string,
  options: AdminApiOptions = {}
): Promise<T> {
  const token = getDexCreatorToken();
  if (!token)
    throw new Error(
      "No wallet session token was found. Log in with an admin wallet first."
    );

  const payload = await orderlyApi<T & { success?: boolean; message?: string }>(
    {
      endpoint,
      method: options.method || "GET",
      body: options.body,
      token,
      baseUrl: getOrderlyEnvConfig().dexApiBaseUrl,
    }
  );

  if (payload && typeof payload === "object" && payload.success === false) {
    throw new Error(payload.message || "Admin request failed.");
  }

  return payload as T;
}

function formatDate(value?: string) {
  if (!value) return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

function formatShort(value?: string | null, start = 8, end = 6) {
  if (!value) return "-";
  if (value.length <= start + end + 3) return value;
  return `${value.slice(0, start)}...${value.slice(-end)}`;
}

function formatNumber(value?: number) {
  return Number(value || 0).toLocaleString();
}

function getDexName(dex: Dex) {
  return dex.brokerName || dex.brokerId || "Unnamed DEX";
}

function getRepoName(repoUrl?: string | null) {
  const match = repoUrl?.match(/github\.com\/[^/]+\/([^/#?]+)/i);
  return match?.[1]?.replace(/\.git$/i, "") || "";
}

function canCreateBroker(dex: Dex) {
  return Boolean(dex.repoUrl) && (!dex.brokerId || dex.brokerId === "demo");
}

function builderActionLabel(action: BuilderAction) {
  if (action === "assignBroker") return "Assign broker ID";
  if (action === "updateRepo") return "Update repo name";
  if (action === "customDomainOverride") return "Override custom domain";
  if (action === "deleteFrontend") return "Delete frontend repo";
  if (action === "recreateRepo") return "Recreate repository";
  if (action === "recreateConfig") return "Recreate config";
  if (action === "repairBrokerBinding") return "Repair broker binding";
  return "Create broker ID";
}

function builderActionDescription(action: BuilderAction) {
  if (action === "assignBroker")
    return "Search for a DEX, then assign or replace its broker ID.";
  if (action === "updateRepo")
    return "Search for a DEX with a frontend repository, then update the repository name.";
  if (action === "customDomainOverride")
    return "Search for a DEX, then override or clear its custom domain.";
  if (action === "deleteFrontend")
    return "Search for a frontend DEX, then delete its frontend/repo record. The backend broker can continue running.";
  if (action === "recreateRepo")
    return "Re-fork the template into the same repository name when the GitHub repo was deleted but the database record is intact.";
  if (action === "recreateConfig")
    return "Sync generated config files in an existing repository from database state without re-forking.";
  if (action === "repairBrokerBinding")
    return "Repair DEX records when on-chain broker creation succeeded but the request timed out. Updates the DEX record, transaction hash, and GitHub config.";
  return "Search for an eligible graduated DEX, then create a broker ID after verifying the payment transaction.";
}

function getDeploymentUrl(dex: Dex) {
  const customDomain = dex.customDomain || dex.customDomainOverride;
  if (customDomain) return `https://${customDomain}`;
  const repoName = getRepoName(dex.repoUrl);
  return repoName ? `https://dex.orderly.network/${repoName}` : "";
}

async function copyToClipboard(text: string, label: string) {
  try {
    await navigator.clipboard.writeText(text);
    toast({ title: `${label} copied.` });
  } catch {
    toast({
      title: `Failed to copy ${label.toLowerCase()}.`,
      variant: "destructive",
    });
  }
}

function fieldClassName(tone: "default" | "danger" = "default") {
  return `h-10 border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-primary) placeholder:text-(--fg-muted) ${tone === "danger" ? "focus-visible:border-red-400" : "focus-visible:border-[#BC87FF]"}`;
}

function SectionCard({
  title,
  description,
  children,
  tone = "default",
}: {
  title: string;
  description?: string;
  children: React.ReactNode;
  tone?: "default" | "warning" | "danger" | "success";
}) {
  const toneClass =
    tone === "danger"
      ? "border-red-500/25 bg-red-500/8"
      : tone === "warning"
        ? "border-[rgba(217,171,82,0.28)] bg-[rgba(217,171,82,0.08)]"
        : tone === "success"
          ? "border-[#1DF6B5]/25 bg-[#1DF6B5]/8"
          : "border-(--line-subtle) bg-(--bg-surface-primary)";

  return (
    <section className={`rounded-2xl border ${toneClass}`}>
      <div className="border-b border-(--line-subtle) px-5 py-4">
        <h2 className="text-base font-semibold text-(--fg-primary)">{title}</h2>
        {description && (
          <p className="mt-1 text-sm leading-6 text-(--fg-secondary)">
            {description}
          </p>
        )}
      </div>
      <div className="p-5">{children}</div>
    </section>
  );
}

